const results = [];

for (const item of $input.all()) {
  const subject     = item.json.subject                 || '';
  const htmlBody    = item.json.body?.content           || '';
  const bodyPreview = item.json.bodyPreview             || '';
  const receivedAt  = item.json.receivedDateTime        || '';
  const emailId     = item.json.id                      || '';

  const plainBody = htmlBody
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi,  '&')
    .replace(/&lt;/gi,   '<')
    .replace(/&gt;/gi,   '>')
    .replace(/\s+/g,     ' ')
    .trim();

  const bodyText = plainBody || bodyPreview;
  const subjectClean = subject.replace(/^(FW|RE|ENC|FWD):\s*/i, '').trim();

  const deviceMatch = subjectClean.match(/^(.+?):\s*WAN/i);
  const dispositivo = deviceMatch ? deviceMatch[1].trim() : 'Desconhecido';

  const siteMatch = dispositivo.match(/(?:UCG|UDM)[\s\w]*\s*-\s*(.+)/i);
  const siteName  = siteMatch ? siteMatch[1].trim() : dispositivo;

  // Detecta tipo de alerta
  const isFailover = /Failover\s+Active/i.test(subjectClean);
  const isRestored = /\bRestored\b/i.test(subjectClean);

  let wan, isp, porta, status;
  let wan_reserva = null, isp_reserva = null;

  if (isFailover) {
    // Ex: "WAN1 (Vivo) on port 5 is down and WAN2 (Claro NET) is now active."
    const fMatch = bodyText.match(
      /WAN(\d+)\s*\(([^)]+)\)\s+on\s+port\s+(\d+)\s+is\s+down\s+and\s+WAN(\d+)\s*\(([^)]+)\)/i
    );
    if (fMatch) {
      wan         = `WAN${fMatch[1]}`;
      isp         = fMatch[2].trim();
      porta       = fMatch[3];
      wan_reserva = `WAN${fMatch[4]}`;
      isp_reserva = fMatch[5].trim();
    } else {
      const wanM = subjectClean.match(/(WAN\d+)/i);
      wan = wanM ? wanM[1].toUpperCase() : 'Desconhecido';
      isp = 'Desconhecido';
      porta = 'Desconhecido';
    }
    status = 'FAILOVER';

  } else {
    const wanMatch = subjectClean.match(/(WAN\d+)/i);
    wan = wanMatch ? wanMatch[1].toUpperCase() : 'Desconhecido';

    const ispMatch = bodyText.match(/WAN\d+\s*\(([^)]+)\)/i);
    isp = ispMatch ? ispMatch[1].trim() : 'Desconhecido';

    const portMatch = bodyText.match(/on\s+port\s+(\d+)/i);
    porta = portMatch ? portMatch[1] : 'Desconhecido';

    status = isRestored ? 'RESTORED' : 'DOWN';
  }

  const timeMatch = bodyText.match(
    /((?:Jan(?:uary)?|Feb(?:ruary)?|Mar(?:ch)?|Apr(?:il)?|May|Jun(?:e)?|Jul(?:y)?|Aug(?:ust)?|Sep(?:tember)?|Oct(?:ober)?|Nov(?:ember)?|Dec(?:ember)?)\s+\d{1,2},\s*\d{4}\s+at\s+[\d:]+\s*[AP]M)/i
  );

  let horario = receivedAt;
  if (timeMatch) {
    const rawStr = timeMatch[1].trim().replace(/\s+at\s+/i, ' ');
    const raw = new Date(rawStr);
    if (!isNaN(raw)) {
      horario = raw.toLocaleString('pt-BR', {
        timeZone: 'America/Sao_Paulo',
        day: '2-digit', month: '2-digit', year: '2-digit',
        hour: '2-digit', minute: '2-digit', second: '2-digit',
        hour12: false
      });
    } else {
      horario = timeMatch[1].trim();
    }
  }

  const emoji = status === 'DOWN' ? '🔴' : status === 'FAILOVER' ? '🟡' : '🟢';

  const tituloTicket = isFailover
    ? `Alerta UniFi ${dispositivo} - ${wan} Down (Failover ${wan_reserva} Ativo)`
    : `Alerta UniFi ${dispositivo} - ${wan} Down`;

  const resumoReserva = wan_reserva ? ` → Failover: ${isp_reserva} (${wan_reserva})` : '';
  const resumo = `${emoji} [${status}] ${dispositivo} — ${isp} (${wan})${resumoReserva} às ${horario}`;

  results.push({
    json: {
      dispositivo,
      siteName,
      wan,
      isp,
      porta,
      wan_reserva,
      isp_reserva,
      status,
      horario,
      emoji,
      emailId,
      tituloTicket,
      resumo,
      assunto_original: subject
    }
  });
}

return results;

