parameters.jsCode:
const dadosAlerta = $('Loop Over Items1').first().json;
const registros = $input.all().map(i => i.json);

if (registros.length === 0) return [];

// Prioridade de match para o ticket a fechar:
// 1. Mesmo WAN + DOWN/FAILOVER, recente (≤48h)
// 2. FAILOVER onde WAN_Reserva = WAN restaurada, recente
// 3. Qualquer FAILOVER recente do dispositivo

function horasAtras(horario) {
  const [datePart, timePart] = horario.split(', ');
  const [d, m, y] = datePart.split('/');
  const dt = new Date(`20${y}-${m}-${d}T${timePart}-03:00`);
  return (Date.now() - dt.getTime()) / (1000 * 60 * 60);
}

const recentes = registros.filter(r => horasAtras(r.Horario) <= 48);

if (recentes.length === 0) {
  console.log('SKIP: nenhum registro recente (≤48h) encontrado.');
  return [];
}

// Prioridade 1: mesmo WAN, DOWN ou FAILOVER
let pool = recentes.filter(r =>
  r.WAN === dadosAlerta.wan && (r.Status === 'DOWN' || r.Status === 'FAILOVER')
);

// Prioridade 2: FAILOVER onde WAN_Reserva = WAN restaurada
if (pool.length === 0) {
  pool = recentes.filter(r =>
    r.Status === 'FAILOVER' && r.WAN_Reserva === dadosAlerta.wan
  );
}

// Prioridade 3: qualquer FAILOVER recente
if (pool.length === 0) {
  pool = recentes.filter(r => r.Status === 'FAILOVER');
}

// Fallback: qualquer recente
if (pool.length === 0) pool = recentes;

// Pega o mais recente pelo maior id
const registro = pool.reduce((a, b) => (a.id > b.id ? a : b));
const ticketNumber = registro['field_5074'] || registro.ticket_number || registro.Ticket;

if (!ticketNumber) return [];

console.log(`Ticket escolhido: ${ticketNumber} | WAN: ${registro.WAN} | Status: ${registro.Status} | ${registro.Horario}`);

const dataAgora = new Date().toLocaleDateString('pt-BR', {
  timeZone: 'America/Sao_Paulo',
  year: 'numeric', month: '2-digit', day: '2-digit'
}).split('/').reverse().join('-');

return [{
  json: {
    ...dadosAlerta,
    ticket_number: ticketNumber,
    apontamento_date: dataAgora,
    descricao_apontamento: `Internet restaurada automaticamente via UniFi. ${dadosAlerta.dispositivo} - ${dadosAlerta.wan}`,
  }
}];
